const slider=document.getElementById("product-price-range");if(slider){noUiSlider.create(slider,{start:[6e3,1e5],step:1,margin:0,connect:!0,behaviour:"tap-drag",range:{min:0,max:12e4},format:wNumb({decimals:0,prefix:"$ "})});const e=document.getElementById("minCost"),n=document.getElementById("maxCost");slider.noUiSlider.on("update",function(t,i){i?n.value=t[i]:e.value=t[i]}),e.addEventListener("change",function(){slider.noUiSlider.set([null,this.value])}),n.addEventListener("change",function(){slider.noUiSlider.set([null,this.value])})}